package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.tools.api.dto.CodeEnumDTO;
import be.schaubroeck.lpb.tools.corehr.extern.uitgaand.rekenmotor.rekenmotor.RekenmotorConfiguratieDTO;
import be.schaubroeck.lpb.tools.enumtypes.TerugbetalingRszNbMandataris;
import be.schaubroeck.temporal.util.TimeToolkit;
import org.joda.time.LocalDate;
import org.springframework.context.annotation.Lazy;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.List;

import static java.util.stream.Collectors.toList;

@Lazy
@Service
public class RkmCoreHrConfiguratieMapper {

    public static final LocalDate END_DATE_IF_NULL = TimeToolkit.endOfTime().toLocalDate();

    public List<RkmCoreHrConfiguratie> map(List<RekenmotorConfiguratieDTO> rkmCoreHrConfigClientConfig) {
        if (rkmCoreHrConfigClientConfig == null || rkmCoreHrConfigClientConfig.isEmpty()) {
            return Collections.emptyList();
        }
        return rkmCoreHrConfigClientConfig.stream()
                .map(config -> RkmCoreHrConfiguratie.builder()
                        .actualFrom(config.getActualFrom())
                        .actualTo(config.getActualTo() != null ? config.getActualTo() : END_DATE_IF_NULL)
                        .geenInclusiefCodeHasta(config.isGeenInclusiefCodesHaardgeldStandplaats())
                        .gewijzigdeGegevens(config.isGewijzigdeGegevens())
                        .werkgeverId(config.getWerkgeverId())
                        .terugbetalingRszNbMandataris(toTerugbetalingRszNbMandataris(config.getTerugbetalingRszNbMandataris()))
                        .referentieUren(config.getReferentieUren())
                        .rekenWerkbonusPerUurBetaalden(config.isRekenWerkbonusPerUurBetaalden())
                        .isTotalMtcRekenen(config.isTotalMtcRekenen())
                        .build())
                .collect(toList());
    }

    private TerugbetalingRszNbMandataris toTerugbetalingRszNbMandataris(CodeEnumDTO codeEnumDTO) {
        if (codeEnumDTO != null) {
            return TerugbetalingRszNbMandataris.getById(codeEnumDTO.getId());
        } else {
            return null;
        }
    }
}
